agent_output:
{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing classification.",
    "bounded_context": "Shipment Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A parcel moving from a pickup address to a delivery address, progressing through a defined lifecycle of states." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The current lifecycle phase of a shipment: Pending, In Transit, or Delivered." },
      { "term": "Weight Bracket", "definition": "A classification tier (Standard, Heavy, Freight) determined by parcel weight, used for pricing." },
      { "term": "Standard", "definition": "Weight bracket for parcels from 0 (exclusive) to 10 kg (inclusive)." },
      { "term": "Heavy", "definition": "Weight bracket for parcels over 10 kg up to 50 kg (inclusive)." },
      { "term": "Freight", "definition": "Weight bracket for parcels over 50 kg up to the 1000 kg maximum." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no valid parcel movement without an origin and destination. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions follow a strict forward-only lifecycle: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression would corrupt the audit trail and violate the physical reality that a parcel in transit cannot un-transit. This is a state integrity constraint.",
      "testable_assertion": "A shipment in state 'In Transit' cannot transition to 'Pending'. A shipment in state 'Delivered' cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed.",
      "invariant": true,
      "invariant_justification": "Delivery is a finalized real-world event (parcel handed over). Allowing state changes after delivery would break billing, SLA tracking, and chain-of-custody records. This is state integrity.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment must be rejected, regardless of the target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound represents a physical/operational constraint (vehicle capacity, handling equipment limits). Violating this would mean accepting shipments that cannot be physically fulfilled.",
      "testable_assertion": "A shipment with weight <= 0 or weight > 1000 must be rejected at creation and at any update."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = (0, 10] kg; Heavy = (10, 50] kg; Freight = (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "The bracket thresholds are a business pricing policy. A VP could adjust the boundaries (e.g., move Heavy to 0-15 kg) without corrupting system state.",
      "testable_assertion": "A 10 kg parcel is classified as Standard. A 10.01 kg parcel is classified as Heavy. A 50 kg parcel is classified as Heavy. A 50.01 kg parcel is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment begins in the Pending state.",
      "invariant": true,
      "invariant_justification": "Creating a shipment directly in 'In Transit' or 'Delivered' would bypass pickup logistics and audit. The initial state is a lifecycle integrity constraint.",
      "testable_assertion": "Upon successful creation, a shipment's state must be 'Pending'."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address, delivery address, and weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is persisted in state 'Pending' with weight bracket 'Standard'"
    },
    {
      "id": "AC-2",
      "given": "A shipment creation request with no pickup address",
      "when": "The system validates the request",
      "then": "The creation is rejected with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A shipment creation request with no delivery address",
      "when": "The system validates the request",
      "then": "The creation is rejected with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in state 'Pending'",
      "when": "The shipment transitions to 'In Transit'",
      "then": "The state is updated to 'In Transit' successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in state 'In Transit'",
      "when": "An attempt is made to transition back to 'Pending'",
      "then": "The transition is rejected and the shipment remains 'In Transit'"
    },
    {
      "id": "AC-6",
      "given": "A shipment in state 'In Transit'",
      "when": "The shipment transitions to 'Delivered'",
      "then": "The state is updated to 'Delivered' successfully"
    },
    {
      "id": "AC-7",
      "given": "A shipment in state 'Delivered'",
      "when": "Any state change is attempted (to 'Pending' or 'In Transit')",
      "then": "The transition is rejected and the shipment remains 'Delivered'"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight of 0 kg",
      "when": "The system validates the request",
      "then": "The creation is rejected with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight of -5 kg",
      "when": "The system validates the request",
      "then": "The creation is rejected with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-10",
      "given": "A shipment creation request with weight of 1001 kg",
      "when": "The system validates the request",
      "then": "The creation is rejected with a validation error indicating weight exceeds the 1000 kg maximum"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight of 10 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as 'Standard'"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as 'Heavy'"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight of 50 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as 'Heavy'"
    },
    {
      "id": "AC-14",
      "given": "A shipment with weight of 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as 'Freight'"
    },
    {
      "id": "AC-15",
      "given": "A shipment with weight of 1000 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as 'Freight' and the shipment is accepted (boundary valid)"
    },
    {
      "id": "AC-16",
      "given": "A shipment in state 'Pending'",
      "when": "An attempt is made to transition directly to 'Delivered'",
      "then": "The transition is rejected — shipments must pass through 'In Transit' first"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard per the bracket definition (0, 10] kg." },
    { "scenario": "Weight is exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy per the bracket definition (10, 50] kg." },
    { "scenario": "Weight is exactly 1000 kg (upper limit)", "expected_behavior": "Accepted and classified as Freight. This is the maximum allowed weight." },
    { "scenario": "Weight is a fractional value like 0.001 kg", "expected_behavior": "Accepted — weight is positive and within range. Classified as Standard." },
    { "scenario": "Pending shipment attempts to skip directly to Delivered", "expected_behavior": "Rejected. The spec explicitly describes a forward-only lifecycle (Pending → In Transit → Delivered), implying intermediate states cannot be skipped." },
    { "scenario": "Pickup and delivery addresses are identical", "expected_behavior": "Ambiguous — the spec does not address this. Likely should be rejected as it represents no real parcel movement, but requires product confirmation." },
    { "scenario": "Weight is updated after shipment creation (e.g., re-weigh at depot)", "expected_behavior": "Ambiguous — the spec does not address mutability of weight post-creation. If allowed, bracket reclassification and re-pricing would be required." },
    { "scenario": "Addresses are updated after shipment is In Transit", "expected_behavior": "Ambiguous — the spec is silent on address mutability. In logistics, redirect-in-transit is a common operation but may have different business rules." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect bracket assignment means revenue leakage (undercharging) or customer disputes (overcharging). The bracket boundaries are the core pricing engine input.",
    "operational": "The forward-only state machine ensures operational clarity — dispatchers, drivers, and warehouse staff can trust shipment status. Allowing state regression would corrupt routing, scheduling, and capacity planning.",
    "user": "Customers expect shipment status to monotonically progress. A shipment reverting from 'In Transit' to 'Pending' would erode trust and generate support tickets. Clear weight limits prevent booking shipments that cannot be physically handled.",
    "risk": "Primary risk is incorrect state transitions corrupting downstream systems (billing, SLA reporting, driver dispatch). Secondary risk is weight bracket boundary errors causing systematic pricing errors at scale.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "Pricing accuracy, shipment status visibility, trust in delivery commitments." },
      { "group": "Recipients", "impact": "Delivery reliability and accurate tracking status." },
      { "group": "Operations / Dispatch", "impact": "Rely on state machine correctness for routing decisions, vehicle loading, and capacity planning." },
      { "group": "Finance / Billing", "impact": "Weight bracket accuracy directly determines invoice amounts and revenue recognition." },
      { "group": "Drivers / Couriers", "impact": "Weight limits ensure parcels are within safe handling and vehicle capacity constraints." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec clearly defines the state machine, weight constraints, and bracket classification. However, it is silent on several important operational details: address mutability, weight mutability post-creation, whether Pending→Delivered skip is allowed, and what constitutes a valid address. The bracket boundary semantics (inclusive/exclusive) required inference from 'over X kg' language.",
    "high_confidence_areas": [
      "Forward-only state lifecycle (Pending → In Transit → Delivered)",
      "Delivered is terminal",
      "Weight must be positive and <= 1000 kg",
      "Three weight brackets exist with defined thresholds"
    ],
    "low_confidence_areas": [
      "Whether Pending can skip directly to Delivered",
      "Exact boundary semantics for weight brackets (inclusive vs exclusive at 10 and 50 kg)",
      "Whether weight or addresses can be modified after creation",
      "Whether identical pickup and delivery addresses are valid"
    ],
    "assumptions": [
      "The bracket boundary '0-10 kg is standard' means (0, 10] — i.e., 10 kg is included in Standard, not Heavy",
      "The phrase 'over 50 kg' means strictly greater than 50, making 50 kg Heavy not Freight",
      "Pending → Delivered directly is not allowed — the lifecycle is sequential, not just forward-reachable",
      "Weight is required at creation time alongside addresses",
      "A shipment's initial state is always Pending"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says '0-10 kg is standard' and 'over 50 kg is freight' but does not explicitly state whether boundary values (exactly 10 kg, exactly 50 kg) belong to the lower or upper bracket. The natural language reading of 'over 50 kg' suggests >50 is Freight and <=50 is Heavy, but '0-10 kg' could mean <10 or <=10.",
      "affected_stakeholders": ["Finance / Billing", "Senders (Customers)"],
      "options": ["10 kg is Standard, 50 kg is Heavy (boundaries belong to lower bracket)", "10 kg is Heavy, 50 kg is Freight (boundaries belong to upper bracket)"],
      "recommendation": "Adopt '10 kg is Standard, 50 kg is Heavy' — the phrasing 'over 50 kg' strongly implies >50 for Freight, and symmetrically 10 kg stays in Standard. Confirm with product manager."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not state whether a shipment can skip from Pending directly to Delivered without passing through In Transit. In logistics, this could occur for in-store pickups or same-location transfers.",
      "affected_stakeholders": ["Operations / Dispatch", "Senders (Customers)"],
      "options": ["Allow Pending → Delivered (supports edge workflows)", "Require Pending → In Transit → Delivered (strict sequential lifecycle)"],
      "recommendation": "Require sequential transitions (Pending → In Transit → Delivered). The spec describes a transit-based delivery process, and skipping In Transit would undermine tracking and SLA measurement. Confirm with product manager."
    },
    {
      "type": "missing_context",
      "description": "The spec is silent on whether shipment attributes (weight, pickup address, delivery address) can be modified after creation, and if so, under which states. Weight changes would trigger bracket reclassification and repricing.",
      "affected_stakeholders": ["Finance / Billing", "Operations / Dispatch", "Senders (Customers)"],
      "options": ["Immutable after creation", "Mutable only while Pending", "Mutable until Delivered"],
      "recommendation": "Allow modification only while Pending. Once In Transit, the parcel is physically moving and changes would disrupt operations. Confirm with product manager."
    }
  ],

  "rejection_reasons": []
}
